(()=>{'use strict';
const T=v=>String(v??'').trim(),N=v=>Number(String(v??'').replace(/,/g,''))||0,F=n=>N(n).toLocaleString('th-TH'),B=n=>N(n).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2});
const sorter=new Intl.Collator('th-u-kn-true',{numeric:true,sensitivity:'base'});let rows=[],meta={},lastPayload=null;
function $(s){return document.querySelector(s)}
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function norm(s){return T(s).toLowerCase().replace(/[\s_\-./()[\]:]+/g,'')}
function realTele(r){const tele=T(r.tele),ps=T(r.ps);if(!tele)return false;const kt=norm(tele),kp=norm(ps);if(kt&&kp&&(kt===kp||kp.includes(kt)||kt.includes(kp)))return false;return !!(r.isTele||tele)}
function datestr(s){const p=T(s).split('-');return p.length===3?`${p[2]}/${p[1]}/${p[0]}`:s}
function filters(){return{start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:T($('#psSelect')?.value),receiver:T($('#storeSelect')?.value),brand:T($('#brandSelect')?.value),type:T($('#typeSelect')?.value),q:T($('#q')?.value).toLowerCase()}}
function appKey(){return meta.id||lastPayload?.version_id||meta.file_name||''}
function stateKey(){return 'doit-json:'+appKey()}
function manualKey(){return 'doit-manual-v1:'+appKey()}
function historyKey(){return 'doit-print-history-v1:'+appKey()}
function state(){try{return JSON.parse(localStorage.getItem(stateKey())||'{}')}catch{return{}}}
function saveState(s){localStorage.setItem(stateKey(),JSON.stringify(s||{}))}
function manuals(){try{return JSON.parse(localStorage.getItem(manualKey())||'[]')}catch{return[]}}
function saveManual(a){localStorage.setItem(manualKey(),JSON.stringify(a||[]))}
function history(){try{return JSON.parse(localStorage.getItem(historyKey())||'[]')}catch{return[]}}
function saveHistory(a){localStorage.setItem(historyKey(),JSON.stringify(a||[]))}
function pk(r){return [r.brand,r.size,r.code||r.sku,r.sku,r.type].join('|')}
function baseRows(visible=true){const f=filters();return rows.filter(r=>!realTele(r)&&(!f.start||r.date>=f.start)&&(!f.end||r.date<=f.end)&&(!f.ps||r.ps===f.ps)&&(!visible||!f.brand||r.brand===f.brand)&&(!visible||!f.type||r.type===f.type)&&(!visible||!f.q||[r.date,r.inv,r.code,r.sku,r.store,r.ps,r.brand,r.size,r.type].join(' ').toLowerCase().includes(f.q)))}
function group(visible=true){const m=new Map();baseRows(visible).forEach(r=>{const k=pk(r);let g=m.get(k);if(!g){g={poolKey:k,brand:r.brand,size:r.size,code:r.code,sku:r.sku,type:r.type,qty:0,amt:0,unit:r.unit||0,bills:new Set(),stores:new Set()};m.set(k,g)}g.qty+=N(r.qty);g.amt+=N(r.amt);g.unit=g.qty&&g.amt?g.amt/g.qty:g.unit;g.bills.add(r.inv);g.stores.add(r.store)});return [...m.values()].sort((a,b)=>sorter.compare(a.brand,b.brand)||sorter.compare(a.size,b.size)||sorter.compare(a.code||'',b.code||'')||sorter.compare(a.sku,b.sku)||sorter.compare(a.type,b.type))}
function recFromKey(k){return String(k).split('|')[3]||''}
function pkFromKey(k){return String(k).split('|').slice(4).join('|')}
function scopeHead(){const f=filters();return[f.start,f.end,f.ps].join('|')+'|'}
function manualInScope(){const f=filters();return manuals().filter(x=>(!f.start||x.start===f.start)&&(!f.end||x.end===f.end)&&(!f.ps||x.ps===f.ps)&&(!f.receiver||x.store===f.receiver))}
function deliveryLines(){const f=filters(),st=state(),send=st.send||{},gmap=new Map(group(false).map(g=>[g.poolKey,g])),out=[];Object.keys(send).filter(k=>k.startsWith(scopeHead())).forEach(k=>{const q=N(send[k]);if(q<=0)return;const g=gmap.get(pkFromKey(k));const rec=recFromKey(k);if(g&&rec)out.push({store:rec,code:g.code||'',name:g.sku,brand:g.brand,size:g.size,type:g.type,qty:q,unit:g.unit||0,manual:false})});manualInScope().forEach(x=>out.push({store:x.store,code:x.code||'',name:x.name,brand:x.brand||'เพิ่มเอง',size:x.size||'',type:x.type||'MANUAL',qty:N(x.qty),unit:N(x.unit),manual:true,id:x.id}));return out.sort((a,b)=>sorter.compare(a.store,b.store)||sorter.compare(a.brand,b.brand)||sorter.compare(a.size,b.size)||sorter.compare(a.code,b.code)||sorter.compare(a.name,b.name))}
function exportCsv(e){e?.preventDefault?.();e?.stopImmediatePropagation?.();const out=[['ชื่อรายการ','จำนวน']];group(true).forEach(g=>out.push([g.sku,g.qty]));manualInScope().forEach(x=>out.push([x.name,N(x.qty)]));if(out.length===1){alert('ไม่พบข้อมูลในตารางตามตัวกรองปัจจุบัน');return}const csv='\ufeff'+out.map(a=>a.map(x=>'"'+String(x??'').replace(/"/g,'""')+'"').join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8'}));a.download='doit-pick-list-name-qty.csv';a.click()}
function ensurePrintCss(){if($('#doitPrintCss274'))return;const st=document.createElement('style');st.id='doitPrintCss274';st.textContent='body.printMode>*:not(#doitPrintOverlay){display:none!important}#doitPrintOverlay{position:fixed;inset:0;z-index:9999;background:#eef2f7;overflow:auto}#doitPrintOverlay .bar{position:sticky;top:0;background:#087b34;color:#fff;padding:10px;display:flex;gap:8px;justify-content:space-between;align-items:center}#doitPrintOverlay .bar button{font-weight:900;padding:8px 12px;border-radius:8px;border:1px solid #fff}#doitPrintOverlay .page{background:#fff;width:194mm;min-height:281mm;margin:10px auto;padding:8mm;page-break-after:always}#doitPrintOverlay .head{display:flex;justify-content:space-between;border-bottom:2px solid #111;margin-bottom:8px;padding-bottom:6px}#doitPrintOverlay .shop{font-size:16px;font-weight:900}#doitPrintOverlay table{width:100%;border-collapse:collapse;font-size:12px}#doitPrintOverlay th,#doitPrintOverlay td{border:1px solid #111;padding:4px}#doitPrintOverlay th{background:#eee}#doitPrintOverlay .r{text-align:right}#doitPrintOverlay .price{width:75px;text-align:right}#doitPrintOverlay .sign{display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px;margin-top:24px;text-align:center}#doitPrintOverlay .sign div{border-top:1px solid #111;padding-top:6px}@media print{#doitPrintOverlay{position:static;background:#fff;overflow:visible}#doitPrintOverlay .bar{display:none}#doitPrintOverlay .page{margin:0;width:auto;box-shadow:none}#doitPrintOverlay .price{border:0}}';document.head.appendChild(st)}
function closePrint(){document.body.classList.remove('printMode');$('#doitPrintOverlay')?.remove()}
function buildPrint(){ensurePrintCss();$('#doitPrintOverlay')?.remove();const data=deliveryLines();if(!data.length){alert('ยังไม่ได้ใส่จำนวนส่งจริงให้ร้านใด');return}const by={};data.forEach(l=>(by[l.store]??=[]).push(l));const ov=document.createElement('div');ov.id='doitPrintOverlay';const bar=document.createElement('div');bar.className='bar';bar.innerHTML='<b>แก้ราคา/หน่วยก่อน แล้วค่อยกดสั่งปริ้น</b><span><button id="doitClosePrint">ปิด</button> <button id="doitConfirmPrint">ยืนยันปริ้นแล้ว/ปิดบิลร้านนี้</button> <button id="doitPrintNow">สั่งปริ้น</button></span>';ov.appendChild(bar);const f=filters();Object.entries(by).forEach(([store,items],bi)=>{const pg=document.createElement('section');pg.className='page';pg.innerHTML=`<div class="head"><div><b>ใบส่งสินค้า</b><div class="shop">ร้าน: ${esc(store)}</div></div><div>วันที่: ${esc(datestr(f.end||f.start))}<br>PS: ${esc(f.ps||'ทั้งหมด')}<br>ใบที่: ${bi+1}</div></div><table><thead><tr><th>#</th><th>รหัส</th><th>รายการ</th><th>จำนวน</th><th>ราคา/หน่วย</th><th>รวม</th></tr></thead><tbody></tbody></table><div class="sign"><div>ผู้จัดของ</div><div>ผู้ส่ง</div><div>ผู้รับสินค้า</div></div>`;const tb=pg.querySelector('tbody');items.forEach((l,i)=>{const tr=document.createElement('tr');tr.innerHTML=`<td>${i+1}</td><td>${esc(l.code)}</td><td>${esc(l.name)}${l.manual?' <b>(เพิ่มเอง)</b>':''}<br><small>${esc(l.brand)} · ${esc(l.size)} · ${esc(l.type)}</small></td><td class="r">${F(l.qty)}</td><td class="r"></td><td class="r total">0.00</td>`;const inp=document.createElement('input');inp.className='price';inp.type='number';inp.step='0.01';inp.value=String(Math.round(N(l.unit)*100)/100);inp.dataset.qty=l.qty;tr.children[4].appendChild(inp);tb.appendChild(tr)});tb.insertAdjacentHTML('beforeend','<tr><td colspan="5" class="r"><b>รวม</b></td><td class="r billTotal">0.00</td></tr>');ov.appendChild(pg)});document.body.appendChild(ov);document.body.classList.add('printMode');function recalc(){ov.querySelectorAll('.page').forEach(pg=>{let sum=0;pg.querySelectorAll('.price').forEach(inp=>{const v=N(inp.value)*N(inp.dataset.qty);sum+=v;inp.closest('tr').querySelector('.total').textContent=B(v)});pg.querySelector('.billTotal').textContent=B(sum)})}ov.querySelectorAll('.price').forEach(i=>i.oninput=recalc);$('#doitClosePrint').onclick=closePrint;$('#doitPrintNow').onclick=()=>{recalc();setTimeout(()=>window.print(),80)};$('#doitConfirmPrint').onclick=()=>closeSelectedReceiver(true);recalc()}
function closeSelectedReceiver(saveHist){const f=filters();if(!f.receiver){alert('กรุณาเลือกร้านจริงก่อนปิดบิลหรือล้างร้าน');return}const st=state(),head=[f.start,f.end,f.ps,f.receiver].join('|')+'|',removed=[];['send','add','pull'].forEach(k=>{const obj=st[k]||{};Object.keys(obj).forEach(x=>{if(x.startsWith(head)){removed.push({map:k,key:x,qty:N(obj[x])});delete obj[x]}});st[k]=obj});const ms=manuals(),keep=[];ms.forEach(x=>{if(x.store===f.receiver&&x.start===f.start&&x.end===f.end&&x.ps===f.ps)removed.push({map:'manual',item:x});else keep.push(x)});if(!removed.length){alert('ร้านนี้ไม่มีรายการค้างในช่วงวันที่/PS นี้');return}if(saveHist){const h=history();h.unshift({at:new Date().toISOString(),store:f.receiver,start:f.start,end:f.end,ps:f.ps,items:deliveryLines().filter(x=>x.store===f.receiver)});saveHistory(h.slice(0,200))}saveState(st);saveManual(keep);alert(saveHist?'ปิดบิลและเก็บเข้า History แล้ว':'ล้างรายการของร้านนี้แล้ว');location.reload()}
function addManual(){const f=filters();if(!f.receiver){alert('กรุณาเลือกร้านจริงก่อนเพิ่มสินค้านอก DOIT');return}const name=prompt('ชื่อสินค้า/รายการที่ต้องการเพิ่ม');if(!T(name))return;const qty=N(prompt('จำนวนส่ง', '1'));if(qty<=0)return alert('จำนวนต้องมากกว่า 0');const unit=N(prompt('ราคา/หน่วย ถ้าไม่รู้ใส่ 0', '0'));const code=prompt('รหัส SKU ถ้ามี', '')||'';const brand=prompt('กลุ่ม/แบรนด์ ถ้ามี', 'เพิ่มเอง')||'เพิ่มเอง';const arr=manuals();arr.push({id:Date.now(),store:f.receiver,start:f.start,end:f.end,ps:f.ps,name:T(name),qty,unit,code:T(code),brand:T(brand),size:'',type:'MANUAL'});saveManual(arr);alert('เพิ่มสินค้านอก DOIT แล้ว จะออกในใบส่งและ Export');}
function guardRedo(e){try{document.querySelector('#redo')?.onclick?.call(document.querySelector('#redo'),e)}catch(err){e?.preventDefault?.();e?.stopImmediatePropagation?.();alert('Redo มีปัญหาจาก cache เก่า ให้รีเฟรชหน้าแล้วลองใหม่')}}
function installButtons(){const a=document.querySelector('.actions');if(a&&!$('#manualAddBtn')){const b=document.createElement('button');b.id='manualAddBtn';classButton(b,'+ เพิ่มสินค้านอก DOIT');b.onclick=addManual;a.prepend(b)}if(a&&!$('#clearStoreBtn')){const b=document.createElement('button');b.id='clearStoreBtn';classButton(b,'ล้างเฉพาะร้านนี้');b.onclick=()=>closeSelectedReceiver(false);a.prepend(b)}if(a&&!$('#closeBillBtn')){const b=document.createElement('button');b.id='closeBillBtn';classButton(b,'ยืนยันปริ้นแล้ว/ปิดบิล');b.onclick=()=>closeSelectedReceiver(true);a.prepend(b)}const p=$('#prepPrint'),x=$('#exportCsv'),r=$('#redo');if(p&&!p.dataset.fix274){p.dataset.fix274='1';p.addEventListener('click',e=>{e.preventDefault();e.stopImmediatePropagation();buildPrint()},true)}if(x&&!x.dataset.fix274){x.dataset.fix274='1';x.addEventListener('click',exportCsv,true)}if(r&&!r.dataset.fix274){r.dataset.fix274='1';r.addEventListener('click',guardRedo,true)}}
function classButton(b,t){b.type='button';b.className='outline';b.textContent=t}
function wrap(){if(!window.DOIT_JSON_APP||window.DOIT_JSON_APP.__printFix274)return false;const app=window.DOIT_JSON_APP,old=app.load.bind(app);app.load=(payload,m={})=>{lastPayload=payload;meta=m||{};const all=(payload.rows||payload||[]).map(r=>({date:T(r.date),inv:T(r.inv),store:T(r.store),tele:T(r.tele),isTele:!!r.isTele,ps:T(r.ps),code:T(r.code),sku:T(r.sku),brand:T(r.brand),size:T(r.size),type:T(r.type)||'INVC',qty:N(r.qty),unit:N(r.unit),amt:N(r.amt)}));rows=all;const filtered=all.filter(r=>!realTele(r));const next=Array.isArray(payload)?filtered:{...payload,rows:filtered};old(next,m);setTimeout(()=>{installButtons();window.DOIT_TELESALE_DRAWER?.loadRows(all,{start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:T($('#psSelect')?.value)})},100)};app.__printFix274=true;return true}
function boot(){installButtons();if(!wrap())setTimeout(boot,300)}document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();})();